function e(e){return e*Math.PI/180}function t(t,n){let r=e(n.latitude-t.latitude),i=e(n.longitude-t.longitude),a=e(t.latitude),o=e(n.latitude),s=Math.sin(r/2)**2+Math.cos(a)*Math.cos(o)*Math.sin(i/2)**2;return 6371e3*(2*Math.atan2(Math.sqrt(s),Math.sqrt(1-s)))}function n(e){return!Number.isFinite(e)||e==null?`N/D`:e<1e3?`${Math.round(e)} m`:`${(e/1e3).toFixed(1)} km`}export{t as n,n as t};